const fs = require('fs');
const path = require('path');

function compute_loan_metrics(loan) {
  const principal = loan.principal;
  const annual_rate_pct = loan.annual_rate_pct;
  const term_months = loan.term_months;
  const origination_fee = loan.origination_fee;

  const monthly_rate = annual_rate_pct / 100 / 12;

  let monthly_payment;
  if (monthly_rate === 0) {
    monthly_payment = principal / term_months;
  } else {
    const numerator = principal * monthly_rate * Math.pow(1 + monthly_rate, term_months);
    const denominator = Math.pow(1 + monthly_rate, term_months) - 1;
    monthly_payment = numerator / denominator;
  }

  monthly_payment = Math.round(monthly_payment * 100) / 100;
  const total_interest = Math.round((monthly_payment * term_months - principal) * 100) / 100;
  const total_paid = Math.round((principal + total_interest + origination_fee) * 100) / 100;

  const discrepancies = [];

  if (monthly_payment !== loan.stated_monthly_payment) {
    discrepancies.push({
      field: "monthly_payment",
      stated: loan.stated_monthly_payment,
      computed: monthly_payment,
      delta: Math.round((monthly_payment - loan.stated_monthly_payment) * 100) / 100
    });
  }

  if (total_interest !== loan.stated_total_interest) {
    discrepancies.push({
      field: "total_interest",
      stated: loan.stated_total_interest,
      computed: total_interest,
      delta: Math.round((total_interest - loan.stated_total_interest) * 100) / 100
    });
  }

  if (total_paid !== loan.stated_total_paid) {
    discrepancies.push({
      field: "total_paid",
      stated: loan.stated_total_paid,
      computed: total_paid,
      delta: Math.round((total_paid - loan.stated_total_paid) * 100) / 100
    });
  }

  return {
    loan_id: loan.loan_id,
    lender: loan.lender,
    computed: {
      monthly_payment: monthly_payment,
      total_interest: total_interest,
      total_paid: total_paid
    },
    discrepancies: discrepancies,
    valid: discrepancies.length === 0
  };
}

const loanPath = '/var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-m0anahhk/loan_calculator/sample_inputs/loan_008.json';
const outputPath = '/var/folders/1q/vdr_cj816z314xnj3bp7w_wr0000gn/T/capture-loan_calculator-m0anahhk/loan_calculator/output.json';

const loan = JSON.parse(fs.readFileSync(loanPath, 'utf8'));
const result = compute_loan_metrics(loan);

fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
console.log(JSON.stringify(result, null, 2));

